      );

      const message = await msgResponse.json();

      // Extract verification link from HTML
      const linkMatch = message.parts[0].body.match(
        /href="([^"]*verify[^"]*)"/,
      );
      return { link: linkMatch?.[1] || "" };
    });
  },
});
